	test('Detect nested regions', () => {
		const lines = [
			'// #region Outer',
			'  // #region Inner',
			'  function foo() {}',
			'  // #endregion',
			'// #endregion'
		];
		assertNamedRegions(lines, [
			{ name: 'Inner', startLineNumber: 2, endLineNumber: 4 },
			{ name: 'Outer', startLineNumber: 1, endLineNumber: 5 }
