			'// #endregion'
		];
		assertNamedRegions(lines, [
			{ name: 'Region', startLineNumber: 1, endLineNumber: 3 }
		]);
	});

	test('Ignore regions with less than 1 line span', () => {
		const lines = [
			'// #region Empty',
			'// #endregion'
		];
		assertNamedRegions(lines, []);
	});
});

